import React from 'react';

function ClickCounter() {
  const [clicks, setClicks] = React.useState(0);
  const handleClick = React.useCallback(() => {
    setClicks(clicks + 1);
  }, [clicks]);
  return (
    <div>
      <p>Clicks: {clicks}</p>
      <button onClick={handleClick}>Click me!</button>
    </div>
  );
}

