import json
from functools import lru_cache

class ClickCounter:
    def __init__(self):
        self.clicks = 0

    def handle_click(self):
        self.clicks += 1

    def render(self):
        return f'Clicks: {self.clicks}'

    def update(self, input_data):
        self.clicks = json.loads(input_data)['clicks']

if __name__ == '__main__':
    import sys
    input_data = sys.stdin.readline().strip()
    click_counter = ClickCounter()
    click_counter.update(input_data)
    while True:
        line = sys.stdin.readline().strip()
        if line == '' or line == 'exit':
            break
        click_counter.handle_click()
        output = click_counter.render()
        print(output)
